firmware_template.source:
#include "wake_word.h"
#include <driver/i2s.h>
#include <esp_heap_caps.h>
#include <esp_log.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include <tensorflow/lite/micro/micro_mutable_op_resolver.h>
#include <tensorflow/lite/schema/schema_generated.h>

#define TAG "wake_word"
#define SAMPLE_RATE 16000
#define STRIDE_MS   20
#define STRIDE_SAMPLES (SAMPLE_RATE * STRIDE_MS / 1000)
#define WINDOW_SIZE  (SAMPLE_RATE)  /* 1 second sliding window */
#define TENSOR_ARENA_SIZE (80 * 1024)
#define I2S_WS  4
#define I2S_SCK 5
#define I2S_SD  7

static bool detected = false;
static float confidence = 0.0f;
static float threshold = 0.85f;
static bool enabled = true;
static int16_t audio_buffer[STRIDE_SAMPLES];
static int16_t sliding_window[WINDOW_SIZE];
static int window_pos = 0;

static uint8_t *tensor_arena = NULL;
static const tflite::Model *model = NULL;
static tflite::MicroInterpreter *interpreter = NULL;
static TfLiteTensor *input_tensor = NULL;
static TfLiteTensor *output_tensor = NULL;

static const uint8_t *model_data = NULL;
static size_t model_size = 0;

static bool load_model_from_spiffs(const char *path) {
  FILE *f = fopen(path, "rb");
  if (!f) { ESP_LOGE(TAG, "Model not found: %s", path); return false; }
  fseek(f, 0, SEEK_END);
  model_size = ftell(f);
  fseek(f, 0, SEEK_SET);
  model_data = (const uint8_t *)heap_caps_malloc(model_size, MALLOC_CAP_SPIRAM);
  if (!model_data) { fclose(f); ESP_LOGE(TAG, "PSRAM alloc failed (%u bytes)", model_size); return false; }
  fread((void *)model_data, 1, model_size, f);
  fclose(f);
  ESP_LOGI(TAG, "Model loaded: %u bytes from %s", model_size, path);
  return true;
}

static bool init_tflite() {
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    ESP_LOGE(TAG, "Model schema mismatch: got %lu, expected %d", model->version(), TFLITE_SCHEMA_VERSION);
    return false;
  }
  tensor_arena = (uint8_t *)heap_caps_malloc(TENSOR_ARENA_SIZE, MALLOC_CAP_SPIRAM);
  if (!tensor_arena) { ESP_LOGE(TAG, "Arena alloc failed"); return false; }
  static tflite::MicroMutableOpResolver<10> resolver;
  resolver.AddConv2D();
  resolver.AddDepthwiseConv2D();
  resolver.AddFullyConnected();
  resolver.AddReshape();
  resolver.AddSoftmax();
  resolver.AddMaxPool2D();
  resolver.AddAveragePool2D();
  resolver.AddRelu();
  resolver.AddLogistic();
  resolver.AddQuantize();
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE);
  interpreter = &static_interpreter;
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    ESP_LOGE(TAG, "AllocateTensors failed"); return false;
  }
  input_tensor = interpreter->input(0);
  output_tensor = interpreter->output(0);
  ESP_LOGI(TAG, "TFLite ready (arena %d KB, input shape [%d])", TENSOR_ARENA_SIZE / 1024, input_tensor->dims->data[1]);
  return true;
}

static void i2s_mic_init() {
  i2s_config_t cfg = {
    .mode = (i2s_mode_t)(I2S_MODE_MASTER | I2S_MODE_RX),
    .sample_rate = SAMPLE_RATE,
    .bits_per_sample = I2S_BITS_PER_SAMPLE_32BIT,
    .channel_format = I2S_CHANNEL_FMT_ONLY_LEFT,
    .communication_format = I2S_COMM_FORMAT_STAND_I2S,
    .intr_alloc_flags = ESP_INTR_FLAG_LEVEL1,
    .dma_buf_count = 4,
    .dma_buf_len = STRIDE_SAMPLES,
  };
  i2s_driver_install(I2S_NUM_0, &cfg, 0, NULL);
  i2s_pin_config_t pins = { .bck_io_num = I2S_SCK, .ws_io_num = I2S_WS, .data_out_num = -1, .data_in_num = I2S_SD };
  i2s_set_pin(I2S_NUM_0, &pins);
}

void wake_word_setup() {
  i2s_mic_init();
  memset(sliding_window, 0, sizeof(sliding_window));
  window_pos = 0;
  if (!load_model_from_spiffs("/spiffs/wake_word.tflite")) {
    ESP_LOGW(TAG, "No model file — detection disabled until OTA delivers model");
    enabled = false;
    return;
  }
  if (!init_tflite()) {
    ESP_LOGE(TAG, "TFLite init failed");
    enabled = false;
    return;
  }
  ESP_LOGI(TAG, "Listening for wake word (threshold=%.2f)", threshold);
}

void wake_word_loop() {
  if (!enabled || !interpreter) return;
  size_t bytes_read = 0;
  int32_t raw[STRIDE_SAMPLES];
  i2s_read(I2S_NUM_0, raw, sizeof(raw), &bytes_read, portMAX_DELAY);
  for (int i = 0; i < STRIDE_SAMPLES; i++) {
    audio_buffer[i] = (int16_t)(raw[i] >> 16);
    sliding_window[window_pos] = audio_buffer[i];
    window_pos = (window_pos + 1) % WINDOW_SIZE;
  }
  int input_len = input_tensor->dims->data[1];
  for (int i = 0; i < input_len && i < WINDOW_SIZE; i++) {
    int idx = (window_pos + i) % WINDOW_SIZE;
    input_tensor->data.f[i] = sliding_window[idx] / 32768.0f;
  }
  if (interpreter->Invoke() != kTfLiteOk) {
    ESP_LOGW(TAG, "Inference failed");
    return;
  }
  confidence = output_tensor->data.f[1];
  if (confidence >= threshold) {
    detected = true;
    ESP_LOGI(TAG, "DETECTED (confidence=%.3f)", confidence);
  }
}

bool wake_word_detected() {
  bool d = detected;
  detected = false;
  return d;
}

float wake_word_confidence() { return confidence; }
void wake_word_set_threshold(float t) { threshold = t; }
void wake_word_enable(bool en) { enabled = en; }
